if (response.error || Number(response.exitCode || 0) !== 0) {
  throw new Error('Local ffmpeg render failed: ' + (response.stderr || response.stdout || response.error || JSON.stringify(response)));
}

const stdout = String(response.stdout || '').trim();
const jsonLine = stdout.split(/\r?\n/).reverse().find((line) => line.trim().startsWith('{'));
if (!jsonLine) {
  throw new Error('Local renderer returned no JSON: ' + JSON.stringify(response));
}

const parsed = JSON.parse(jsonLine);
if (!parsed.ok || !parsed.output_path) {
  throw new Error('Local renderer returned invalid output: ' + JSON.stringify(parsed));
}

return [{
  json: {
    ...base,
    local_render_response: response,
    render_status: 'succeeded',
    output_path: parsed.output_path,
    rendered_video_url: parsed.output_path,
    card_path: parsed.card_path || null,
    bgm_download_path: parsed.audio_path || null,
    render_failed: false,
  },
}];

const fs = require('fs');
const path = require('path');
const base = $('Parse Local Render Result').first().json;
const input = $input.first();
const cfg = base.config || {};
const guardEnabled = Boolean(cfg.allow_youtube_upload && !cfg.dry_run && !cfg.test_mode);
const lockPath = String(cfg.upload_log_path || '').trim() + '.upload.lock';
const token = Date.now().toString(36) + '-' + Math.random().toString(36).slice(2);
const ttlMs = 10 * 60 * 1000;
let uploadGuard = { version: 'upload_guard_v1', acquired: !guardEnabled, enabled: guardEnabled, lock_path: lockPath || null, token: null, reason: guardEnabled ? 'not_acquired' : 'not_required' };

function tryAcquire() {
  if (!guardEnabled) return;
  if (!lockPath) throw new Error('Upload guard requires config.upload_log_path.');
  fs.mkdirSync(path.dirname(lockPath), { recursive: true });
  try {
    const fd = fs.openSync(lockPath, 'wx');
    fs.writeFileSync(fd, JSON.stringify({ token, acquired_at: new Date().toISOString() }), 'utf8');
    fs.closeSync(fd);
    uploadGuard = { ...uploadGuard, acquired: true, token, reason: 'acquired' };
  } catch (error) {
    if (error?.code !== 'EEXIST') throw error;
    let stale = false;
    try {
      const existing = JSON.parse(fs.readFileSync(lockPath, 'utf8'));
      stale = Date.now() - Date.parse(existing.acquired_at || 0) > ttlMs;
    } catch (readError) {
      stale = Date.now() - fs.statSync(lockPath).mtimeMs > ttlMs;
    }
    if (stale) {
      fs.unlinkSync(lockPath);
      return tryAcquire();
    }
    uploadGuard = { ...uploadGuard, acquired: false, reason: 'overlapping_upload_in_progress' };
  }
}

// ALREADY_UPLOADED_GUARD_V1_BEGIN
function findAlreadyUploaded() {
  const title = String(base.pack?.hook_title || '').replace(/\s+/g, ' ').trim();
  const logPath = String(cfg.upload_log_path || '').trim();
  if (!title || !logPath) return null;
  try {
    if (!fs.existsSync(logPath)) return null;
    const rows = fs.readFileSync(logPath, 'utf8').split(/\r?\n/).map((line) => line.trim()).filter(Boolean);
    for (let index = rows.length - 1; index >= 0; index -= 1) {
      let row = null;
      try { row = JSON.parse(rows[index]); } catch (error) { continue; }
      const rowTitle = String(row?.title || '').replace(/\s+/g, ' ').trim();
      if (rowTitle && rowTitle === title && row?.url) {
        return { url: row.url, video_id: row.video_id || null, uploaded_at: row.uploaded_at || null, matched_title: rowTitle };
      }
    }
  } catch (error) {
    return null;
  }
  return null;
}
const alreadyUploaded = guardEnabled ? findAlreadyUploaded() : null;
// ALREADY_UPLOADED_GUARD_V1_END
if (alreadyUploaded) {
  uploadGuard = { ...uploadGuard, acquired: false, reason: 'already_uploaded', already_uploaded: alreadyUploaded };
} else {
  tryAcquire();
}
return [{ json: { ...base, mp4_binary_ready: !!input.binary?.data, upload_guard: uploadGuard, already_uploaded: alreadyUploaded }, binary: input.binary }];

const fs = require('fs');
const base = $('Attach Downloaded MP4').first().json;
const upload = $input.first().json || {};
const videoId = upload.uploadId || upload.id || upload.videoId || upload.items?.[0]?.id || null;
const privacyStatus = base.config?.youtube_privacy_status || 'public';
const guard = base.upload_guard || {};
if (guard.acquired && guard.lock_path && guard.token) {
  try {
    const current = JSON.parse(fs.readFileSync(guard.lock_path, 'utf8'));
    if (current.token === guard.token) fs.unlinkSync(guard.lock_path);
  } catch (error) {
    if (error?.code !== 'ENOENT') throw error;
  }
}
return [{ json: { ...base, upload_guard: { ...guard, released: true }, youtube: { skipped: false, privacy_status: privacyStatus, video_id: videoId, url: videoId ? 'https://www.youtube.com/watch?v=' + videoId : null, raw: upload } } }];

