return [{ json: { ...base, comment: { created: !response.error, id: response.id || response.items?.[0]?.id || null, raw: response, note: 'Top-level comment created. API pin unsupported.' } } }];

const data = $input.first().json;
const dryRun = Boolean(data.config?.test_mode || data.config?.dry_run);
